// ── Visual GPU Phase 4 (ADR-005) ─────────────────────────────────────────────

/** Rust src/vision_backend/types.rs::Rect */
export interface NativeVisionRect {
  x: number
  y: number
  width: number
  height: number
}

/** Rust src/vision_backend/types.rs::RoiInput */
export interface NativeRoiInput {
  trackId: string
  rect: NativeVisionRect
  classHint?: string | null
}

/** Rust src/vision_backend/types.rs::RecognizeRequest */
export interface NativeRecognizeRequest {
  targetKey: string
  /** Session key from `init_session_blocking`. Empty string → legacy dummy path. */
  sessionKey: string
  rois: NativeRoiInput[]
  frameWidth: number
  frameHeight: number
  /** Captured frame RGBA bytes, length = frameWidth * frameHeight * 4.
   *  Empty Buffer → legacy dummy path (no preprocess, stub candidates). */
  frameBuffer: Buffer
  nowMs: number
}

/** Rust src/vision_backend/types.rs::RawCandidate */
export interface NativeRawCandidate {
  trackId: string
  rect: NativeVisionRect
  /** Empty string when class is "icon" or detection found a non-text element. */
  label: string
  /** "text"|"icon"|"mixed"|"button"|"checkbox"|"radio"|"dropdown"|"slider"|"tab"|"label"|"image"|"title"|"other" */
  class: string
  confidence: number
  provisional: boolean
}

/**
 * Rust src/vision_backend/capability.rs::CapabilityProfile
 *
 * Sample for the dogfood machine (RX 9070 XT, Win11 24H2):
 *   { os: "windows", osBuild: 26100, gpuVendor: "AMD", gpuArch: "RDNA4", winml: true, directml: true, ... }
 */
export interface NativeCapabilityProfile {
  os: string
  osBuild: number
  gpuVendor: string
  gpuDevice: string
  gpuArch: string
  gpuVramMb: number
  winml: boolean
  directml: boolean
  rocm: boolean
  cuda: boolean
  tensorrt: boolean
  cpuIsa: string[]
  backendBuilt: boolean
  epsBuilt: string[]
}

// ── Phase 4b-1: EP cascade session init ──────────────────────────────────────

/**
 * Rust src/vision_backend/types.rs::NativeSessionInit
 *
 * Input to `visionInitSession`. `profile` should be obtained from
 * `detectCapability()` so the cascade can select the optimal EP.
 */
export interface NativeSessionInit {
  /** Absolute path to the .onnx file to load. */
  modelPath: string
  /** CapabilityProfile produced by detectCapability(). */
  profile: NativeCapabilityProfile
  /**
   * Optional stable session key for later pool lookup (e.g. "ui_detector:dml-fp16").
   * Pass an empty string for ad-hoc sessions.
   */
  sessionKey: string
}

/**
 * Rust src/vision_backend/types.rs::NativeSessionResult
 *
 * Returned by `visionInitSession`. The Promise **never rejects** — errors are
 * reported via `ok === false` to maintain L5 process isolation.
 */
export interface NativeSessionResult {
  ok: boolean
  /**
   * Set when `ok === true`. Format: "WinML" | "DirectML(0)" | "ROCm(0)" |
   * "CUDA(0)" | "CPU" | "Fallback(reason)"
   */
  selectedEp: string
  /** Set when `ok === false`. Concatenated cascade attempt errors. */
  error?: string | null
  /** Echoed `sessionKey` — use as lookup key for subsequent recognize_rois calls (4b-4+). */
  sessionKey: string
}

// ── ADR-007 P5a: L1 capture ring buffer ──────────────────────────────────────

/** napi 公開する EventEnvelope の TS 側表現。Rust 内部の InternalEvent は
 *  payload を Vec<u8> で所有するが、JS 側では Buffer (fresh allocation) として渡る。 */
export interface NativeEventEnvelope {
  envelopeVersion: number
  eventId: bigint
  wallclockMs: bigint
  subOrdinal: number
  timestampSource: number
  kind: number
  payloadBytes: Buffer
  sessionId?: string | null
  toolCallId?: string | null
}

/** L1 ring buffer のヘルスチェック結果。bench / server_status 用。 */
export interface NativeCaptureStats {
  uptimeMs: bigint
  pushCount: bigint
  dropCount: bigint
  currentBuffered: number
  panicCount: bigint
  eventIdHighWater: bigint
}

/**
 * Lease 4-tuple summary attached to `l1PushToolCallStarted` (ADR-010 P1 S4
 * sub-plan `docs/adr-010-p1-s4-plan.md` §2.3). Mirrors the runtime
 * `EntityLease` (`src/engine/world-graph/types.ts`) minus `expiresAtMs`
 * (commit-time validation has already consumed the TTL) and with
 * `evidenceDigest` truncated to the first 8 hex chars so the L1 ring
 * stays compact when lease-aware tool calls run at high rate.
 *
 * Tail-only Optional parameter on `l1PushToolCallStarted` so existing
 * 4-arg positional callers (`tests/unit/l1-capture.test.ts:163`,
 * `tests/unit/l1-capture-panic-fuzz.test.ts:122,128`) keep compiling
 * unchanged (Round 1 P1-1, sub-plan §2.3).
 */
export interface NativeLeaseTokenSummary {
  entityId: string
  viewId: string
  targetGeneration: string
  evidenceDigestPrefix8: string
}

// ── ADR-015 Phase 3: VBA Extensibility bridge ────────────────────────────────
//
// Mirror types for the napi-rs binding in `src/vba_bridge.rs`. Session
// lifecycle uses integer handle IDs; the TS layer in Phase 4 will wrap
// these into the single `excel` MCP tool action dispatcher.

/** Read-only HKCU / HKLM `AccessVBOM` registry inspection result.
 * Returned by `excelCheckAccessVbom`. Mirrors
 * `engine_vba_bridge::registry::AccessVbomStatus` with `scope` as a
 * String (napi cannot marshal `&'static str` for an object field). */
export interface NativeExcelAccessVbomStatus {
  /** Effective trust state. `true` when either HKCU is 1 or HKLM forces 1. */
  trusted: boolean
  /** `true` only when HKLM is set to 0 (group policy forces denial). */
  lockedByPolicy: boolean
  /** `"hklm-policy"` (HKLM dictates), `"hkcu"` (HKLM unset, HKCU is 1), or `"default"` (neither set). */
  scope: string
}
